const { createApp, json, cors, logger, compress,
	static: serveStatic } = require('zero-http')
const app = createApp()

app.use(logger({ format: 'dev' }))
app.use(cors())
app.use(compress())
app.use(json({ limit: '10kb' }))
app.use(serveStatic(path.join(__dirname, 'public')))

app.get('/', (req, res) => res.json({ hello: 'world' }))

app.ws('/chat', (ws, req) => {
	ws.on('message', msg => ws.send('echo: ' + msg))
})

app.onError((err, req, res, next) => {
	console.error(err)
	res.status(500).json({ error: err.message })
})

// HTTP
app.listen(3000, () => console.log('listening on :3000'))

// HTTPS
app.listen(443, { key: fs.readFileSync('key.pem'), cert: fs.readFileSync('cert.pem') })

const { createApp, Router, json } = require('zero-http')
const app = createApp()
const api = Router()

api.use(json())
api.get('/users', (req, res) => res.json([]))
api.get('/users/:id', (req, res) => res.json({ id: req.params.id }))

// Route chaining
api.route('/items')
	.get((req, res) => res.json([]))
	.post((req, res) => res.status(201).json(req.body))

// HTTPS-only route
api.get('/secret', { secure: true }, (req, res) => res.json({ classified: true }))

app.use('/api', api)
app.listen(3000)

console.log(app.routes())
// [{ method:'GET', path:'/api/users' }, { method:'GET', path:'/api/users/:id' }, ...]

app.get('/demo', (req, res) => {
	res.status(200)
	   .set('X-Custom', 'hello')
	   .type('json')
	   .json({ message: 'ok' })
})

app.get('/page', (req, res) => res.html('<h1>Hello</h1>'))
app.get('/go', (req, res) => res.redirect(301, '/new-location'))

// Open an SSE stream
app.get('/events', (req, res) => {
	const sse = res.sse({ retry: 5000, autoId: true })
	sse.send('hello')
})

const { createApp } = require('zero-http')
const app = createApp()

const clients = new Set()

app.ws('/chat', {
	maxPayload: 64 * 1024,
	pingInterval: 20000,
	verifyClient: (req) => req.headers['x-api-key'] === 'secret'
}, (ws, req) => {
	clients.add(ws)
	ws.data.name = req.query.name || 'anon'
	ws.send('Welcome, ' + ws.data.name + '!')

	ws.on('message', msg => {
		for (const c of clients) {
			if (c !== ws && c.readyState === 1)
				c.send(ws.data.name + ': ' + msg)
		}
	})

	ws.on('close', () => clients.delete(ws))
})

app.listen(3000)

app.get('/events', (req, res) => {
	const sse = res.sse({
		status: 200,
		retry: 5000,
		keepAlive: 30000,
		keepAliveComment: 'ping',
		autoId: true,
		startId: 1,
		pad: 2048,
		headers: { 'X-Stream': 'live' }
	})

	// Send unnamed data event
	sse.send('hello')

	// Send named event with object data
	sse.event('update', { x: 1, y: 2 })

	// Props
	console.log(sse.connected)   // true
	console.log(sse.eventCount)  // 2
	console.log(sse.bytesSent)   // bytes written
	console.log(sse.uptime)      // ms since opened
	console.log(sse.secure)      // true for HTTPS
	console.log(sse.data)        // {} user store

	// Periodic events
	const iv = setInterval(() => sse.event('tick', Date.now()), 1000)
	sse.on('close', () => clearInterval(iv))
})

const { createApp, compress } = require('zero-http')
const app = createApp()

// Compress responses over 512 bytes (brotli > gzip > deflate)
app.use(compress({ threshold: 512, level: 6 }))

// Skip compression for specific routes
app.use(compress({
	filter: (req, res) => !req.url.startsWith('/stream')
}))

app.get('/big', (req, res) => {
	res.json({ data: 'x'.repeat(10000) })
})

app.use(json({
	limit: '10kb',
	strict: true,
	requireSecure: false,
	reviver: (k, v) => {
		if (typeof v === 'string' && /^\d{4}-\d{2}-\d{2}T/.test(v)) return new Date(v)
		return v
	},
	type: 'application/json'
}))

// Simple flat parsing
app.use(urlencoded())

// Extended mode with nested bracket syntax
app.use(urlencoded({
	extended: true,
	limit: '20kb',
	requireSecure: false
}))
// a[b][c]=1  → { a: { b: { c: '1' } } }
// a[]=1&a[]=2 → { a: ['1', '2'] }

app.use(text({ type: 'text/*', limit: '50kb', encoding: 'utf8' }))

app.post('/echo-text', (req, res) => {
	res.text(req.body) // echo back the plain text
})

app.post('/binary', raw({ limit: '5mb' }), (req, res) => {
	console.log(req.body)        // <Buffer ...>
	console.log(req.body.length) // byte count
	res.json({ size: req.body.length })
})

const uploadsDir = path.join(os.tmpdir(), 'my-uploads')

app.post('/upload', multipart({
	dir: uploadsDir,
	maxFileSize: 10 * 1024 * 1024,
	requireSecure: false
}), (req, res) => {
	// req.body.fields  → { desc: 'a photo' }
	// req.body.files   → { file: { originalFilename, storedName, path, contentType, size } }
	res.json({ files: req.body.files, fields: req.body.fields })
})

// Basic static serving
app.use(static(path.join(__dirname, 'public')))

// Full options
app.use(static(path.join(__dirname, 'public'), {
	index: 'index.html',
	maxAge: 3600000,   // 1 hour in ms
	dotfiles: 'ignore',
	extensions: ['html', 'htm'],
	setHeaders: (res, filePath) => {
		res.setHeader('X-Served-By', 'zero-http')
	}
}))

// Allow everything (default)
app.use(cors())

// Restrict to specific origins with credentials
app.use(cors({
	origin: ['https://example.com', '.mysite.com'],
	credentials: true,
	methods: 'GET,POST'
}))
// Origins starting with '.' enable suffix matching:
// '.mysite.com' matches 'api.mysite.com', 'www.mysite.com', etc.

const { fetch } = require('zero-http')

// Simple GET with timeout
const r = await fetch('https://jsonplaceholder.typicode.com/todos/1', {
	timeout: 5000
})
const data = await r.json()
console.log(r.ok, r.status, r.secure, r.url, data)

// POST with auto-serialized JSON body
await fetch('https://httpbin.org/post', {
	method: 'POST',
	body: { hello: 'world' }
})

// HTTPS with custom TLS options
await fetch('https://internal-api.local/data', {
	rejectUnauthorized: false,
	ca: fs.readFileSync('ca.pem')
})

// Download with progress tracking
await fetch('https://example.com/big-file.zip', {
	onDownloadProgress: ({ loaded, total }) =>
		console.log(`${loaded}/${total} bytes`)
})

const { rateLimit } = require('zero-http')

// 100 requests per 15 minutes
app.use(rateLimit({
	windowMs: 15 * 60 * 1000,
	max: 100,
	message: 'Slow down!'
}))

// Per-route limiting with custom key
app.post('/login', rateLimit({
	windowMs: 60000,
	max: 5,
	keyGenerator: (req) => req.body?.username || req.ip
}), (req, res) => {
	res.json({ ok: true })
})

const { logger } = require('zero-http')

// Colorized dev output (default)
app.use(logger())

// Short format with custom log function
app.use(logger({
	format: 'short',
	logger: (msg) => fs.appendFileSync('access.log', msg + '\n')
}))

// Tiny format, no colors
app.use(logger({ format: 'tiny', colors: false }))
